584: void ConnectionManagerImpl::onEvent(Network::ConnectionEvent event) {
585:   if (event == Network::ConnectionEvent::LocalClose) {
586:     stats_.named_.downstream_cx_destroy_local_.inc();
587:   }
588: 
589:   if (event == Network::ConnectionEvent::RemoteClose ||
590:       event == Network::ConnectionEvent::LocalClose) {
591: 
592:     std::string details;
593:     if (event == Network::ConnectionEvent::RemoteClose) {
594:       remote_close_ = true;
595:       stats_.named_.downstream_cx_destroy_remote_.inc();
596:       details = StreamInfo::ResponseCodeDetails::get().DownstreamRemoteDisconnect;
597:     } else {
598:       absl::string_view local_close_reason = read_callbacks_->connection().localCloseReason();
599:       ENVOY_BUG(!local_close_reason.empty(), "Local Close Reason was not set!");
600:       details = fmt::format(
601:           fmt::runtime(StreamInfo::ResponseCodeDetails::get().DownstreamLocalDisconnect),
602:           StringUtil::replaceAllEmptySpace(local_close_reason));
603:     }
604: 
605:     // TODO(mattklein123): It is technically possible that something outside of the filter causes
606:     // a local connection close, so we still guard against that here. A better solution would be to
607:     // have some type of "pre-close" callback that we could hook for cleanup that would get called
608:     // regardless of where local close is invoked from.
609:     // NOTE: that this will cause doConnectionClose() to get called twice in the common local close
610:     // cases, but the method protects against that.
611:     // NOTE: In the case where a local close comes from outside the filter, this will cause any
612:     // stream closures to increment remote close stats. We should do better here in the future,
613:     // via the pre-close callback mentioned above.
614:     doConnectionClose(absl::nullopt, StreamInfo::CoreResponseFlag::DownstreamConnectionTermination,
615:                       details);
616:   }
617: }
