232:   }
233:   if (drain_state_ == DrainState::Closing && streams_.empty() && !codec_->wantsToWrite()) {
234:     // We are closing a draining connection with no active streams and the codec has
235:     // nothing to write.
236:     doConnectionClose(close, absl::nullopt,
237:                       StreamInfo::LocalCloseReasons::get().DeferredCloseOnDrainedConnection);
238:   }
239: }
